// NODE: Approval Request Registrar (Hardened v26.2 - Deterministic ID)
// FIX: Removed randomUUID() to enforce Idempotency.
// TRACE_ID = APPROVAL_ID. Same Trace -> Same ID -> DB Lock.

const crypto = require('crypto');

const input = $json;
const trace_id = input.trace_id;
const advisory_hash = input.advisory_hash;
const selected_channel = input.selected_channel;
const block_4_seal_hash = input.block_4_seal_hash;

// ---- 1. EXTRACT TRANSACTION CONTEXT (ROBUST STRATEGY) ----
const pkg = input.advisory_package || {};
let transaction_context = pkg.transaction_context || null;

// FALLBACK: Recover from UI if structured data was stripped by Adapter
if (!transaction_context && pkg.transaction_ready === true && Array.isArray(pkg.sections)) {
    const alertSection = pkg.sections.find(s => s.type === 'alert_box_critical');

    if (alertSection) {
        // Extract Tool Name
        const titleParts = alertSection.title.split(':');
        const toolName = titleParts.length > 1 ? titleParts[1].trim() : 'UNKNOWN_TOOL';

        // Extract Rationale
        const rationale = alertSection.content || "Emergency action triggered via UI.";

        transaction_context = {
            proposal: toolName,
            rationale: rationale,
            parameters: { target_id: "CUSTOMER_ID" },
            requires_approval: true
        };
    }
}

const has_valid_transaction = transaction_context && 
                              transaction_context.proposal && 
                              transaction_context.proposal !== 'NONE';

// ---- 2. GENERATE DETERMINISTIC APPROVAL ID (THE FIX) ----
// 🛑 REMOVED: crypto.randomUUID()
// ✅ ADDED: Deterministic Hash of trace_id
// This ensures that Trace X ALWAYS equals Approval ID Y.
// If this ID exists in the DB, the next node (Supabase) will throw an error and BLOCK the flow.
const id_hash = crypto.createHash('sha256').update(trace_id).digest('hex').slice(0, 16);
const approval_id = `approval_${trace_id}_${id_hash}`;

// ---- 3. SINGLE TIMESTAMP
const created_at = new Date().toISOString();
const expires_at = new Date(Date.now() + 15 * 60 * 1000).toISOString();

// ---- 4. APPROVAL REQUEST ENVELOPE (IMMUTABLE)
const approval_request = {
  approval_id,
  trace_id,
  advisory_hash,
  selected_channel,
  block_4_seal_hash,
  expires_at,
  approval_ingress_path: "/bank/approval/v1",
  max_approval_age_seconds: 900,
  created_at,
  // CRITICAL: Persist the reconstructed tool instruction
  transaction_execution: has_valid_transaction ? transaction_context : null
};

// ---- 5. CRYPTOGRAPHIC IMMUTABILITY
const approval_request_hash = crypto.createHash('sha256')
  .update(JSON.stringify(approval_request))
  .digest('hex');

const request_integrity_hash = crypto.createHash('sha256')
  .update(`${approval_id}:${advisory_hash}:${trace_id}:${created_at}:${selected_channel}:${block_4_seal_hash}`)
  .digest('hex');

// ---- 6. LEDGER RECORD WITH EXPLICIT STATE
const approval_record = {
  approval_id,
  trace_id,
  advisory_hash,
  block_4_seal_hash,
  selected_channel,
  approval_request_hash, 
  request_integrity_hash,
  created_at,
  expires_at,
  consumed: false,
  state: 'PENDING', 
  approval_request: approval_request 
};

return [{
  json: {
    ...input,
    approval_record,
    approval_request, 
    __ledger_ready: true,
    __crypto_immutable: true,
    __approval_request_hash: approval_request_hash
  }
}];

// NODE: Block 5: Universal Gate (Hybrid - Robust V2)
// SECURITY: Handles both "New Ticket" and "Approval" flows
// FIX: Populates all metadata fields to prevent "undefined" errors downstream.

const item = $input.first();
const payload = item.json.body || item.json;
const approval_id = payload.approval_id;
const now = new Date().toISOString();

// =========================================================
// MODE 1: NEW TICKET GENERATION (Main Flow)
// =========================================================
if (!approval_id) {
    // We are generating a new ticket. We don't have an ID yet.
    // Security Check: Is the upstream Block 4 sealed?
    const isLocked = item.json.__status?.block_4_locked === true || item.json.block_4_seal_hash;

    if (!isLocked) {
        throw new Error("SECURITY_BLOCK: Attempted to process Unsealed Advisory.");
    }

    // SUCCESS: Pass through with FULL metadata
    return [{
        json: {
            ...item.json,
            // Routing Flags
            __flow_context: "NEW_TICKET_GENERATION",
            __gate_status: "PASSED_CREATION_CHECK",
            __approval_eligible: true, // CRITICAL: Forces the IF node to "True" path

            // Logging Metadata (Fixes undefined errors)
            __eligibility_reason: "NEW_TICKET_CREATION_AUTHORIZED",
            __eligibility_checked_at: now
        }
    }];
}

// =========================================================
// MODE 2: APPROVAL VERIFICATION (Webhook Flow)
// =========================================================
// If we are here, we have an approval_id, so we MUST run Anti-Replay logic.

// 1. RETRIEVE DB RECORD
// This MUST be provided by the Supabase node immediately preceding this one.
const db_record = item.json.db_record || item.json; 

// 2. THE "GHOST" CHECK (Anti-Replay Logic)
if (!db_record || db_record.approval_id !== approval_id) {
   // If the DB lookup failed or returned nothing
   throw new Error(`SECURITY_BLOCK: Approval ID ${approval_id} does not exist in ledger.`);
}

// CHECK 1: Is it already used?
if (db_record.status === 'CONSUMED') {
  throw new Error(`REPLAY_ATTACK_DETECTED: Approval ${approval_id} was already consumed at ${db_record.consumed_at}.`);
}

// CHECK 2: Is it strictly PENDING?
if (db_record.status !== 'PENDING') {
   throw new Error(`SECURITY_BLOCK: Invalid approval status: ${db_record.status}`);
}

// 3. PASS-THROUGH FOR HMAC
return [{
  json: {
    ...item.json,
    // Overwrite with IMMUTABLE DB data for security
    advisory_hash: db_record.advisory_hash, 
    trace_id: db_record.trace_id,
    expires_at: db_record.expires_at,
    block_4_seal_hash: db_record.block_4_seal_hash,

    // Routing Flags
    __flow_context: "APPROVAL_VERIFICATION",
    __approval_eligible: true, // Forces "True" path

    // Logging Metadata (Fixes undefined errors)
    __eligibility_reason: "APPROVAL_VERIFIED_AGAINST_LEDGER",
    __eligibility_checked_at: now
  }
}];

const input = $json;
const { advisory_confidence, governance_flags, advisory_hash } = input;

// 1. DATA EXTRACTION
// Safe extraction with fallbacks
const jurisdiction = governance_flags?.jurisdiction || '*';
const confidence = advisory_confidence?.score || 0;

// 2. CHANNEL ARBITRATION RULES
const CHANNEL_RULES = {
  INTERNAL_UI: { min_confidence: 0.1, priority: 3 },
  EMAIL_TEMPLATE: { min_confidence: 0.4, priority: 2 },
  WEBHOOK_DELIVERY: { min_confidence: 0.7, priority: 1 }
};

// 3. SELECTION LOGIC
let selected_channel = 'INTERNAL_UI';
let eligible = ['INTERNAL_UI'];

// ✅ FIX APPLIED: Removed "&& jurisdiction !== '.uz'" 
// Now, if confidence is high (0.7+), it sends a Webhook regardless of country.
if (confidence >= 0.7) {
  selected_channel = 'WEBHOOK_DELIVERY';
  eligible = ['WEBHOOK_DELIVERY', 'EMAIL_TEMPLATE', 'INTERNAL_UI'];
} else if (confidence >= 0.4) {
  selected_channel = 'EMAIL_TEMPLATE';
  eligible = ['EMAIL_TEMPLATE', 'INTERNAL_UI'];
}

// 4. FINAL OUTPUT
return [{
  json: {
    ...input,
    selected_channel,
    eligible_channels: eligible,
    arbitration_reason: `Clean Pass: Selected ${selected_channel} (Confidence: ${confidence})`,
    arbitration_timestamp: new Date().toISOString(),
    arbitration_final: true
  }
}];

const input = $json;
const { dispatch_guard, trace_id } = input;

// ---- Normalized dispatch result
const dispatch_result = {
  status: 'DELIVERED',
  channel: 'INTERNAL_UI',
  dispatch_id: `ui_${dispatch_guard.idempotence_key.slice(0, 16)}`,
  dispatched_at: new Date().toISOString(),
  internal_reference: `adv_${trace_id}`,
  idempotence_key: dispatch_guard.idempotence_key,
  approval_id: dispatch_guard.approval_id,
  advisory_hash: dispatch_guard.advisory_hash
};

return [{
  json: {
    ...input,
    dispatch_result,
    __dispatch_type: 'INTERNAL_UI'
  }
}];

// Analytics Emitter
const input = $json;
const { dispatch_outcome, validated_approval, advisory_confidence, __block_5_complete } = input;

// ---- NON-BLOCKING ANALYTICS EMISSION
try {
  const analytics_payload = {
    event_id: `analytics_${Date.now()}_${dispatch_outcome?.dispatch_id || 'rejected'}`,
    trace_id: input.trace_id,
    dispatch_id: dispatch_outcome?.dispatch_id,
    channel: dispatch_outcome?.channel || validated_approval?.selected_channel,
    status: dispatch_outcome?.status || 'REJECTED',
    confidence_score: advisory_confidence.score,
    approver_role: validated_approval?.approver_role,
    sealed_block_id: __block_5_complete?.seal_id,
    canonical_advisory_hash: validated_approval?.advisory_hash?.slice(0, 16),
    emitted_at: new Date().toISOString(),
    analytics_class: 'NON_BLOCKING_OBSERVABILITY',
    required_for_success: false,
    authoritative: false
  };

  console.log('[ANALYTICS_EMITTED]', JSON.stringify(analytics_payload));
} catch (analyticsError) {
  console.error('[ANALYTICS_ERROR_NON_BLOCKING]', analyticsError.message);
}

return [{
  json: {
    ...input,
    analytics_emission: {
      status: 'EMITTED',
      emission_id: `analytics_${Date.now()}`,
      non_blocking: true,
      audit_compliant: true
    }
  }
}];

// Get the data from the Switch node
const input = $json;
const channel = input.dispatch_guard?.approved_channel;

// Construct a detailed error message
const errorMessage = `INVALID_DISPATCH_CHANNEL: The channel '${channel || 'UNDEFINED'}' is not supported by the current routing logic. 
Supported: INTERNAL_UI, EMAIL_TEMPLATE, WEBHOOK_DELIVERY. 
Trace ID: ${input.trace_id}`;

// Throwing the error stops the workflow and alerts the admin
throw new Error(errorMessage);

