// NODE: Approval Envelope Validator (Smart Diagnostics)
// LOGIC: Distinguishes between Hacking (HMAC Fail) and Expiry (Time Fail)

const stored_record = $json; 
const approval_payload = $json.body;

console.log(`[VALIDATOR] Processing approval: ${stored_record.approval_id}`);

// 1. CHECK: DATA INTEGRITY
if (!approval_payload) {
  throw new Error('PAYLOAD_MISSING: No webhook body found in input');
}

// 2. CHECK: CONSUMED STATUS (Double Spend Protection)
if (stored_record.consumed !== false) {
  throw new Error(`APPROVAL_ALREADY_CONSUMED: This ticket was used on ${stored_record.consumed_at}`);
}

// 3. CHECK: PREVIOUS SECURITY AUDIT
// We verify the flags set by the previous HMAC Verifier node
const security = stored_record.security || {};
const hmac_status = stored_record.hmac_check || {};

if (security.is_authorized !== true) {
    // DIAGNOSTIC FAILURE ROUTING

    // Case A: The Ticket is Expired
    if (security.is_expired) {
        throw new Error(`SECURITY_VIOLATION: TOKEN EXPIRED. 
        Deadline: ${stored_record.expires_at}
        Attempted: ${approval_payload.approval_timestamp}
        (Action: Create a fresh ticket to test this flow)`);
    }

    // Case B: It was already used
    if (security.is_duplicate) {
        throw new Error(`SECURITY_VIOLATION: REPLAY DETECTED. This approval was already consumed.`);
    }

    // Case C: The Cryptography actually failed (Real Attack)
    if (hmac_status.match === false) {
        throw new Error(`SECURITY_VIOLATION: HMAC MISMATCH (Cryptographic Tampering). 
        Received: ${hmac_status.received}
        Calculated: ${hmac_status.calculated}`);
    }

    // Case D: Unknown Fallback
    throw new Error(`SECURITY_VIOLATION: Unauthorized for unknown reason. Check input logs.`);
}

// 4. CHECK: STATE (Case Insensitive)
if (stored_record.state.toUpperCase() !== 'PENDING') {
  throw new Error(`INVALID_STATE: Expected PENDING, got ${stored_record.state}`);
}

// 5. SUCCESS OUTPUT
return [{
  json: {
    valid: true,
    reason: "AUTHORIZED",
    action: "EXECUTE_DISPATCH",

    // Identity & Audit Trail
    approval_id: stored_record.approval_id,
    trace_id: stored_record.trace_id,
    approver_id: approval_payload.approver_id,
    approver_role: approval_payload.approver_role,

    // Decision Details
    decision: approval_payload.decision,
    approval_timestamp: approval_payload.approval_timestamp,

    meta: {
      timestamp: new Date().toISOString(),
      validator: "5.1-smart-gate",
      expires_at: stored_record.expires_at
    }
  }
}];

