const crypto = require('crypto');

// --- 1. KEY CONFIGURATION (SECURE HYBRID) ---
// We try to get the key from n8n Variables first, then System Env, then fallback.
const BANK_HMAC_SECRET = $vars.HMAC_SECRET || process.env.HMAC_SECRET ;

if (!BANK_HMAC_SECRET) {
    throw new Error("CRITICAL: HMAC_SECRET is missing from both $vars and process.env");
}

// --- 2. PROCESS LOOP (BATCH MODE) ---
// We handle the data as a batch (requires "Execute Once" ON)
const items = $input.all();

return items.map(item => {
    const data = item.json;
    // Handle both direct webhook body or nested body structure
    const webhook = data.body || data;

    if (!webhook || !webhook.approval_hmac) {
        // We return a failed state instead of crashing, so the workflow can log the security event
        return {
            json: {
                ...data,
                security: { is_authorized: false, error: "MISSING_HMAC" },
                audit_label: 'VERIFICATION_FAILED'
            }
        };
    }

    // --- 3. HMAC RECONSTRUCTION ---
    // We use the exact same fields and order as the Generator
    // We use safe access (|| '') to prevent null errors on missing fields
    const hmacData = [
        webhook.approval_id,
        data.advisory_hash,
        webhook.trace_id,
        webhook.approver_id,
        webhook.approval_timestamp,
        webhook.decision
    ].map(val => String(val || '').trim()).join(':');

    const calculatedHmac = crypto
        .createHmac('sha256', BANK_HMAC_SECRET)
        .update(hmacData, 'utf8')
        .digest('hex');

    // --- 4. VALIDATION LOGIC (HARDENED) ---

    // SECURITY UPGRADE: Constant-Time Comparison
    // Prevents timing attacks where hackers guess the key by measuring processing time.
    const targetBuffer = Buffer.from(calculatedHmac);
    const inputBuffer = Buffer.from(webhook.approval_hmac);

    let hmacMatches = false;
    try {
        if (targetBuffer.length === inputBuffer.length) {
            hmacMatches = crypto.timingSafeEqual(targetBuffer, inputBuffer);
        }
    } catch (e) {
        hmacMatches = false;
    }

    // Check expiry if it exists (Auto-Pilot might not set expiry on the payload, but DB record has it)
    const expiresAt = data.expires_at || data.approval_request?.expires_at;
    const isExpired = expiresAt ? (new Date() > new Date(expiresAt)) : false;

    const isAlreadyConsumed = data.consumed === true;

    // Full authorization check
    const authorized = hmacMatches && !isExpired && !isAlreadyConsumed;

    // --- 5. OUTPUT ---
    return {
        json: {
            ...data,
            hmac_check: {
                received: webhook.approval_hmac,
                calculated: calculatedHmac,
                match: hmacMatches
            },
            security: {
                is_authorized: authorized,
                is_expired: isExpired,
                is_duplicate: isAlreadyConsumed
            },
            // Final Audit Label for the next node
            audit_label: authorized ? 'CRYPTO_VERIFIED' : 'VERIFICATION_FAILED'
        }
    };
});

const crypto = require('crypto');

// Parse the validated_approval string from the previous node
const input = $json;
const validated = JSON.parse(input.validated_approval);

// 1. Generate the Idempotence Key (Unique fingerprint for this dispatch)
const approved_channel = input.approval_request.selected_channel;
const idempotence_key = crypto.createHash('sha256')
  .update(`${validated.approval_id}:${approved_channel}:${validated.trace_id}:${input.advisory_hash}`)
  .digest('hex');

// 2. Prepare the payload for the Supabase Lock node
return {
  idempotence_key,
  approved_channel,
  approval_id: validated.approval_id,
  trace_id: validated.trace_id,
  advisory_hash: input.advisory_hash,
  decision: validated.decision,
  // Pass through the original input to keep data flowing
  parent_data: input 
};

return {
  status: "TERMINATED",
  reason: "Transaction already processed or state invalid",
  idempotence_key: $json.idempotence_key,
  timestamp: new Date().toISOString()
};

// NODE: Logic: Prepare Finalizer (Hardened v23)
// RESILIENCE: Decoupled from specific node names. Uses direct input flow.

const item = $input.first();
const inputData = item.json;

// 1. RECOVER CONTEXT
// In n8n, if previous nodes are merged correctly, their data is available in the input.
// We look for 'dispatch_guard' which should be passed down.
const dispatchGuard = inputData.dispatch_guard || {};

// 2. CHECK DISPATCH SUCCESS
// Gmail/Telegram usually returns an 'id' or 'message_id' on success.
const isSuccess = !!(inputData.id || inputData.message_id || inputData.ok); 
const final_status = isSuccess ? 'dispatched' : 'failed';
const dispatch_id = inputData.id || inputData.message_id || `dispatch_${Date.now()}`;

return {
  json: {
    idempotence_key: dispatchGuard.idempotence_key || "unknown_key",
    approval_id: dispatchGuard.approval_id || inputData.approval_id || "unknown_approval",
    final_status,
    dispatch_id,
    dispatch_result: inputData, // The actual response from Gmail/Telegram
    approved_channel: dispatchGuard.approved_channel || "UNKNOWN",
    trace_id: inputData.trace_id || dispatchGuard.trace_id,

    // Pass through full original context for the next node (Audit Logging)
    original_full_data: inputData 
  }
};

