const crypto = require('crypto');

// --- 1. KEY CONFIGURATION ---
const secret = $vars.HMAC_SECRET || process.env.HMAC_SECRET;
if (!secret) throw new Error("CRITICAL: HMAC_SECRET missing.");

const items = $input.all();

return items.map(item => {
    const inputData = item.json;
    const dbRecord = inputData; 

    // --- 2. EXTRACT CONTEXT (HARDENED) ---
    const ticketData = dbRecord.approval_request || {};

    // Check if we actually have data to analyze
    const hasContext = ticketData.subject || ticketData.body || ticketData.transaction_execution;
    const subject = (ticketData.subject || "").toLowerCase();

    let decision = "APPROVED";
    let ai_reasoning = "Standard validation.";

    // --- 3. THE BRAIN (Zero-Trust Logic) ---

    if (inputData.body && inputData.body.approval_hmac) {
        // Human Override
        decision = inputData.body.decision || "REJECTED";
        ai_reasoning = "Manual intervention by risk officer.";
    } else {
        // Auto-Pilot
        const approver_id = "revenant_ai_core";
        const timestamp = new Date().toISOString();

        // 🛑 SECURITY RULE 1: MISSING CONTEXT = REJECT
        // If we lost the subject/body, we cannot verify safety. BLOCK IT.
        if (!hasContext) {
            decision = "REJECTED";
            ai_reasoning = "SECURITY LOCK: Missing context in approval request. Fail-safe rejection.";
        } 
        // 🛑 SECURITY RULE 2: THREAT DETECTION
        else {
            const riskKeywords = ['replay', 'attack', 'fraud', 'scam', 'hacked', 'duplicate', 'deadbeef'];
            const isHighRisk = riskKeywords.some(w => subject.includes(w));

            if (isHighRisk) {
                decision = "REJECTED";
                ai_reasoning = "SECURITY LOCK: Threat indicators detected. Auto-Rejection enforced.";
            } else {
                decision = "APPROVED";
                ai_reasoning = "Low Risk request. Auto-resolution applied.";
            }
        }

        // SIGNATURE
        const hmacParts = [
            dbRecord.approval_id,
            dbRecord.advisory_hash,
            dbRecord.trace_id,
            approver_id,
            timestamp,
            decision
        ].map(val => String(val || '').trim()).join(':');

        const hmac = crypto.createHmac('sha256', secret).update(hmacParts).digest('hex');

        return {
            json: {
                body: {
                    approval_id: dbRecord.approval_id,
                    decision,
                    approver_id,
                    approver_role: "ai_governance_bot",
                    approval_timestamp: timestamp,
                    approval_hmac: hmac,
                    trace_id: dbRecord.trace_id,
                    ai_reasoning
                },
                method_used: "AUTO_PILOT_HARDENED",
                ai_analysis: ai_reasoning,
                ...dbRecord
            }
        };
    }
});

